  1	import { useState, FC, KeyboardEvent } from 'react';
  2	
  3	import { RESTApi } from '@API/REST.api';
  4	import { I18nNamespace } from '@config/config';
  5	import { TooltipInfoButton } from '@core/components/HelpTooltip';
  6	import { createConnectorRequest } from '@core/utils/createCRD';
  7	import useValidatedInput from '@hooks/useValidation';
  8	import { ConnectorCrdParams, ConnectorParams, ConnectorSpec } from '@interfaces/CRD_Connector';
  9	import { HTTPError } from '@interfaces/REST.interfaces';
 10	import {
 11	  Form,
 12	  FormGroup,
 13	  TextInput,
 14	  ActionGroup,
 15	  Button,
 16	  FormAlert,
 17	  Alert,
 18	  Checkbox,
 19	  Card,
 20	  CardTitle,
 21	  Title,
 22	  CardBody
 23	} from '@patternfly/react-core';
 24	import { useMutation } from '@tanstack/react-query';
 25	import { useTranslation } from 'react-i18next';
 26	
 27	interface ConnectorCrdAttributes extends ConnectorSpec {
 28	  name?: string;
 29	  resourceVersion?: string;
 30	}
 31	
 32	const ConnectorForm: FC<{
 33	  onSubmit: () => void;
 34	  onCancel: () => void;
 35	  title: string;
 36	  connectorName?: string;
 37	  attributes?: ConnectorCrdAttributes;
 38	}> = function ({ onSubmit, onCancel, connectorName, attributes, title }) {
 39	  const { t } = useTranslation(I18nNamespace);
 40	
 41	  const [name, setName] = useState(attributes?.name || '');
 42	  const [routingKey, setRoutingKey] = useState(attributes?.routingKey || '');
 43	  const [selector, setSelector] = useState(attributes?.selector || '');
 44	  const [host, setHost] = useState(attributes?.host || '');
 45	  const [port, setPort] = useState<number | string>(attributes?.port || '');
 46	  const [tlsCredentials, setTlsCredentials] = useState(attributes?.tlsCredentials || '');
 47	  const [includeNotReadyPods, setIncludeNotReadyPod] = useState(attributes?.includeNotReadyPods || false);
 48	
 49	  const { validated, validateInput } = useValidatedInput();
 50	
 51	  const mutationCreate = useMutation({
 52	    mutationFn: (data: ConnectorParams) => RESTApi.createOrUpdateConnector(data, connectorName),
 53	    onError: (data: HTTPError) => {
 54	      validateInput(data.descriptionMessage);
 55	    },
 56	    onSuccess: onSubmit
 57	  });
 58	
 59	  const handleSubmit = () => {
 60	    const key = selector ? 'selector' : 'host';
 61	    const value = selector || host;
 62	
 63	    const data: ConnectorCrdParams = createConnectorRequest({
 64	      metadata: {
 65	        name,
 66	        resourceVersion: attributes?.resourceVersion
 67	      },
 68	      spec: {
 69	        routingKey,
 70	        [key]: value,
 71	        port: Number(port),
 72	        tlsCredentials,
 73	        includeNotReadyPods
 74	      }
 75	    });
 76	
 77	    mutationCreate.mutate(data);
 78	  };
 79	
 80	  const handleChangeName = (value: string) => {
 81	    setName(value);
 82	  };
 83	
 84	  const handleChangeSelector = (value: string) => {
 85	    setSelector(value);
 86	  };
 87	
 88	  const handleChangeHost = (value: string) => {
 89	    setHost(value);
 90	  };
 91	
 92	  const handleChangeRoutingKey = (value: string) => {
 93	    setRoutingKey(value);
 94	  };
 95	
 96	  const handleChangePort = (value: string) => {
 97	    setPort(value);
 98	  };
 99	
100	  const handleChangeTlsCredentials = (value: string) => {
101	    setTlsCredentials(value);
102	  };
103	
104	  const handleKeyPress = (event: KeyboardEvent) => {
105	    if (event.key === 'Enter' && !!(name && port)) {
106	      event.preventDefault(); // Prevents the default Enter key behavior
107	      handleSubmit();
108	    }
109	  };
110	
111	  const canSubmit = !!(name && port);
112	
113	  return (
114	    <Card isPlain>
115	      <CardTitle>
116	        <Title headingLevel="h1">{t(title)}</Title>
117	      </CardTitle>
118	      <CardBody>
119	        <Form isHorizontal onKeyDown={handleKeyPress} data-testid="connector-form">
120	          <FormGroup fieldId="name-input" isRequired label={t('Name')} title="">
121	            <TextInput
122	              aria-label="form name input"
123	              value={name}
124	              onChange={(_, value) => handleChangeName(value)}
125	              isDisabled={!!connectorName}
126	            />
127	          </FormGroup>
128	
129	          <FormGroup fieldId="include-not-ready-checkbox">
130	            <Checkbox
131	              aria-label="form include not ready checkbox"
132	              id="include-not-ready checkbox"
133	              label={t('Include server pods that are not in the ready state')}
134	              onChange={() => setIncludeNotReadyPod(!includeNotReadyPods)}
135	              isChecked={includeNotReadyPods}
136	            />
137	          </FormGroup>
138	
139	          <FormGroup
140	            fieldId="port-input"
141	            isRequired
142	            label={t('Port')}
143	            labelIcon={<TooltipInfoButton content={t('tooltipPort')} />}
144	            title=""
145	          >
146	            <TextInput aria-label="form port input" value={port} onChange={(_, value) => handleChangePort(value)} />
147	          </FormGroup>
148	
149	          <FormGroup
150	            fieldId="routing-key-input"
151	            label={t('Routing key')}
152	            labelIcon={<TooltipInfoButton content={t('tooltipRoutingKey')} />}
153	            title=""
154	          >
155	            <TextInput
156	              aria-label="form routing key input"
157	              value={routingKey}
158	              onChange={(_, value) => handleChangeRoutingKey(value)}
159	            />
160	          </FormGroup>
161	
162	          <FormGroup
163	            fieldId="selector-input"
164	            label={t('Selector')}
165	            labelIcon={<TooltipInfoButton content={t('tooltipConnectorSelector')} />}
166	            title=""
167	          >
168	            <TextInput
169	              aria-label="form selector input"
170	              value={selector}
171	              onChange={(_, value) => handleChangeSelector(value)}
172	              placeholder="app="
173	            />
174	          </FormGroup>
175	
176	          <FormGroup
177	            fieldId="host-input"
178	            label={t('Host')}
179	            labelIcon={<TooltipInfoButton content={t('tooltipConnectorHost')} />}
180	            title=""
181	          >
182	            <TextInput aria-label="form host input" value={host} onChange={(_, value) => handleChangeHost(value)} />
183	          </FormGroup>
184	
185	          <FormGroup
186	            fieldId="tls-secret-input"
187	            label={t('TLS secret')}
188	            labelIcon={<TooltipInfoButton content={t('tooltipTlsCredentials')} />}
189	            title=""
190	          >
191	            <TextInput
192	              aria-label="form TLS secret input"
193	              value={tlsCredentials}
194	              onChange={(_, value) => handleChangeTlsCredentials(value)}
195	            />
196	          </FormGroup>
197	
198	          {validated && (
199	            <FormAlert>
200	              <Alert variant="danger" title={t('An error occurred')} aria-live="polite" isInline>
201	                {validated}
202	              </Alert>
203	            </FormAlert>
204	          )}
205	
206	          <ActionGroup style={{ display: 'flex' }}>
207	            <Button variant="primary" onClick={handleSubmit} isDisabled={!canSubmit}>
208	              {t('Submit')}
209	            </Button>
210	            <Button variant="link" onClick={onCancel}>
211	              {t('Cancel')}
212	            </Button>
213	          </ActionGroup>
214	        </Form>
215	      </CardBody>
216	    </Card>
217	  );
218	};
219	
220	export default ConnectorForm;

